import { NgModule } from '@angular/core';
import { HTTP_INTERCEPTORS, HttpClientModule } from '@angular/common/http';
import { AUTH_OPTIONS, PeAuthOptions } from '../declarations/index';
import { PeAuthInterceptor } from './pe-auth.interceptor';
import { PeAuthService } from './pe-auth.service';
import { CookieModule } from 'ngx-cookie';
import { PeAuthGuardService } from './pe-auth-guard.service';
import { PeAuthComponent } from './pe-auth.component';
import { PeAuthTypeFactory } from './pe-auth.type.factory';
import { PeInterceptService } from './pe-intercept.service';

@NgModule({
  imports: [
    CookieModule.forRoot(),
    HttpClientModule
  ],
  declarations: [
    PeAuthComponent
  ],
  exports: [
    PeAuthComponent
  ]
})
export class PeAuthModule {
  
  static forRoot(options: PeAuthOptions = {}): any {
    return {
      ngModule: PeAuthModule,
      providers : [
        PeInterceptService,
        PeAuthTypeFactory,
        PeAuthService,
        PeAuthGuardService,
        { provide: HTTP_INTERCEPTORS, useClass: PeAuthInterceptor, multi: true },
        { provide: AUTH_OPTIONS, useValue: options }
      ],
    };
  }
  
}
