import { PeAuthType, KitSSOOptions } from '../declarations/index';
import { searchParams } from '../utils/utils';
import { formatCookieName } from './utils/cookie';

export class KitSSOType implements PeAuthType {

    ready: Promise<KitSSOType>;
  
    cxnUrl: string;
    
    autoReload = true;
    
    cookieName = 'userToken';
    
    private static readonly COOKIE_SUFFIXE: any = {
        agent: 'A'
    };
    
    private _options: KitSSOOptions;
    
    constructor(kitSSOOptions: KitSSOOptions, mode: string, redirect: string) {
        this.cookieName = formatCookieName(this.cookieName, kitSSOOptions.cadre, KitSSOType.COOKIE_SUFFIXE[mode]);
        this._options = kitSSOOptions;
        this.cxnUrl = this.buildCxnUrl(redirect);
        this.ready = Promise.resolve(this);
    }

    getTokenFromCookie(cookie: any) {
        return typeof cookie === 'string' ? JSON.parse(cookie) : cookie;
    };
    
    getTokenFromUrl(url: any, callback: (token:any) => void) {
        let token;
        try {
            token = JSON.parse(searchParams(url)['j_username'])
        } catch (e) {
            token = null;
        }
        callback(token);
    };
    
    isValidToken(token:any, time: number) {
        let isValid;
        try {
            const h = this._options.hasOwnProperty("tokenValidityDuration") ? this._options.tokenValidityDuration : 24;
            isValid = (Date.now() - token['attributs']['timestamp'] < 1000*60*60*h) && token['resultatAuthent'] === true;
        } catch (e) {
            isValid = false;
        }
        return isValid;
    };

    buildAuthorization(token: any, mode: string) {
        return 'Bearer ' + mode + JSON.stringify(token);
    }

    logout(token: any, callback: ()=>void) {
        callback();
    }

    private buildCxnUrl(redirect: string) {
        let url = this._options.kitSSOUrl;
        url += (this._options.kitSSOUrl.indexOf('?') > -1 ? '&' : '?') + 'referer=' + encodeURIComponent(redirect);
        return url;
    }
}