import { Component, ElementRef, OnInit, OnDestroy, Input } from '@angular/core';
import { Router, RouterStateSnapshot } from '@angular/router';
import { PeAuthService } from './pe-auth.service';
import { PeAuthSubject } from '../declarations/pe-auth.subject';
import { Observable, Subscription } from 'rxjs';
import { PeInterceptService } from './pe-intercept.service';

@Component({
    selector: 'pe-auth',
    template: ''
})
export class PeAuthComponent implements OnInit, OnDestroy { 
	  
  @Input() type: string;
  @Input() mode: string;
  @Input() defaultRoute: any[];
  @Input() errorRoute: any[];
  @Input() maxRetryRoute: any[];
  @Input() onConnect: (token: string, refreshToken: boolean) => Observable<boolean> | Promise<boolean> | boolean;
  
  private _connect: Subscription;
  private _secureRoute: RouterStateSnapshot;

  constructor(
    private router: Router,
    private peAuthService: PeAuthService,
    private peInterceptService: PeInterceptService,
    private element: ElementRef
  ) {
    this._secureRoute = this.peInterceptService.secureRoute;
  }

	ngOnInit() {
    if (this.onConnect) this.peAuthService.on("connect", this.onConnect);
		this._connect = this.peAuthService.connect(this.type, this.mode, this.element.nativeElement).subscribe( (data: PeAuthSubject) => {
      switch (data.status) {
        case PeAuthService.CXN_SUCCESS:
          if (this._secureRoute === null) {
            this.router.navigate(this.defaultRoute ? this.defaultRoute : ['']);
          } else {
            this.router.navigateByUrl(this._secureRoute.url);
          }
          break;
        case PeAuthService.CXN_ECHEC:
          if (this.errorRoute) this.router.navigate(this.errorRoute);    
          break;
        case PeAuthService.CXN_MAX_RETRY:
          if (this.maxRetryRoute || this.errorRoute) this.router.navigate(this.maxRetryRoute ? this.maxRetryRoute : this.errorRoute);
          break;
      }
		});
  }
    
  ngOnDestroy() {
    this._connect.unsubscribe();
  }
}
