import { Injectable, RendererFactory2, Renderer2, NgZone } from '@angular/core';
import { CookieService, CookieOptions } from 'ngx-cookie';
import { PeAuthSubject, PeAuthType } from '../declarations/index';
import { Observable, BehaviorSubject } from 'rxjs';
import { getEncapsulationAttr } from '../utils/utils';
import { PeAuthTypeFactory } from './pe-auth.type.factory';

@Injectable()
export class PeAuthService {
    
  static readonly CXN_OFF = "off";
  static readonly CXN_PROGRESS = "progress";
  static readonly CXN_ECHEC = "echec";
  static readonly CXN_MAX_RETRY = "max-retry";
  static readonly CXN_SUCCESS = "success";

  //Init the first state to OFF.
  private _time = 0;
  private _type: string = null;
  private _mode: string = null;
  private _status = PeAuthService.CXN_OFF;
  private _token: any = null;
  private _nbAttempt = 0;
  private _subject = new BehaviorSubject<PeAuthSubject>({ status: this._status, token: this._token, refreshToken: false, attempt: this._nbAttempt });
    
  private _cookieOptions: CookieOptions;
  private _authType: PeAuthType;

  private _iframe: any;
  private _iframeLoadListener: ()=>void;
  private _windowMessageListener: ()=>void;

  private _renderer: Renderer2;

  private _onConnect: (token: string, refreshToken: boolean, attempt: number) => Observable<boolean> | Promise<boolean> | boolean = () => true;
    
  constructor(
    private peAuthTypeFactory:PeAuthTypeFactory,
    private cookieService: CookieService,
    private rendererFactory: RendererFactory2,
    private ngZone: NgZone
  ) {
    this._renderer = this.rendererFactory.createRenderer(null, null);
    this._cookieOptions = {
        path: '/',
        domain: window.location.hostname.split('.').splice(-2).join('.'),
        secure: window.location.protocol === 'https:'
    };
  }

  on(event: "connect", fn: (token: string, refreshToken: boolean, attempt: number) => Observable<boolean> | Promise<boolean> | boolean) {
    switch (event) {
      case "connect":
        this._onConnect = fn;
        break;
    }
  }

  private afterCxn(token: string, status: string, refreshToken: boolean): Promise<void> {
    return new Promise((resolve, reject) => {

      function onError(e: any) {
        console.error(e);
        resolve(false);
      }

      if (status === PeAuthService.CXN_SUCCESS) {
        try {
          const res = this._onConnect(token, refreshToken, this._nbAttempt);
          if (this.isObservable(res)) {
            const sub = (res as Observable<boolean>).subscribe(isConnect => {
              resolve(isConnect);
              setTimeout(() => {
                if (sub) {
                  sub.unsubscribe();
                }
              }, 0);
            }, onError);
          } else if (this.isPromise(res)) {
            (res as Promise<boolean>).then(resolve).catch(onError);
          } else {
            resolve(res);
          }
        } catch (e) {
          onError(e);
        } 
      } else {
        resolve(false);
      }
    }).then(connect => {
      const isSuccess = this._status === PeAuthService.CXN_SUCCESS; 
      if (!connect && isSuccess) {
        this._status = PeAuthService.CXN_ECHEC;
      }
      this._subject.next({ status: this._status, token: this._token, refreshToken: refreshToken, attempt: this._nbAttempt });
      if (isSuccess) {
        this._nbAttempt = 0;
      }
    });
  }

  private isPromise(obj: any): boolean {
    return !!obj && typeof obj.then === 'function';
  }
  private isObservable(obj: any): boolean {
    return !!obj && typeof obj.subscribe === 'function';
  }

  isConnected(): boolean {
    return this._status === PeAuthService.CXN_SUCCESS && this._authType && this._authType.isValidToken(this._token, this._time);
  }

  getStatus(): Observable<PeAuthSubject> {
    return this._subject;
  }

  get status() : string {
    return this._status;
  }

  get type(): string {
    return this._type;
  }

  get mode(): string {
    return this._mode;
  }

  get authorizationHeader(): string {
    return this._authType && this._token ? this._authType.buildAuthorization(this._token, this._mode) : '';
  }

  get loginRoute(): any[] {
    return this.peAuthTypeFactory.loginRoute;
  }

  private clear() {
    const currentStatus = this._status;
    this._time    = 0; 
    this._type    = null;
    this._mode    = null;
    this._status  = PeAuthService.CXN_OFF;
    this._token   = null;
    this._nbAttempt = 0;
    if (this._authType) {
      this.cookieService.remove(this._authType.cookieName, this._cookieOptions);
    }
    if (currentStatus !== PeAuthService.CXN_OFF) {
      this._subject.next({ status: this._status, token: this._token, refreshToken: false, attempt: this._nbAttempt });
    }
  }

  logout(): Observable<PeAuthSubject> {
    if (this._authType) {
      this._authType.logout(this._token, () => {
        this.clear() 
      });
    } else {
      this.clear();
    }
    return this._subject;
  }

  private inProgress(refreshToken: boolean) {
    this._status = PeAuthService.CXN_PROGRESS;
    this._nbAttempt++;
    this._subject.next({ status: this._status, token: this._token, refreshToken: refreshToken, attempt: this._nbAttempt });
  }

  connect(type: string, mode: string, container?: HTMLElement): Observable<PeAuthSubject> {
    if (this._type !== type || this._mode !== mode || this._status !== PeAuthService.CXN_PROGRESS) {
      const refreshToken = false;
      
      this._token = null;
      this._type = type;
      this._mode = mode;
      this._nbAttempt = 0;
      this.inProgress(refreshToken);

      this.peAuthTypeFactory.getPeAuthType(type, mode).ready.then(authType => {
        this._authType = authType;
        this.authByUrl(document.location.href).then(() => {
          this.afterCxn(this._token, this._status, false);
        }).catch(() => {
          this.ngZone.runOutsideAngular(()=> {
            if (!this.authByCookie()) {
              this.auth(container ? container : document.body, refreshToken);
            }
          });
        });
      });
    }
    return this._subject;
  }

  refreshToken(container?: HTMLElement): Observable<PeAuthSubject> {
    if (!this._authType) throw 'Connexion required.';
    if (this._status !== PeAuthService.CXN_PROGRESS) {
      const refreshToken = true;
      if (this._nbAttempt === (this.peAuthTypeFactory.maxRetry)) {
        this._status = PeAuthService.CXN_MAX_RETRY;
        this._subject.next({ status: this._status, token: this._token, refreshToken: refreshToken, attempt: this._nbAttempt });
      } else {
        this._token = null;
        this.cookieService.remove(this._authType.cookieName, this._cookieOptions);
        
        this.inProgress(refreshToken);
        this.ngZone.runOutsideAngular(()=> {
          setTimeout(() => {
            this.auth(container ? container : document.body, refreshToken);
          }, this._nbAttempt > 1 ? 500 : 0);
        });
      }
    }
    return this._subject;
  }

  private getIframeParentNode() {
    let parentNode = null;
    if (this._iframe) {
      if (this._iframe.window === this._iframe) {
        parentNode = this._iframe.parent;
      } else {
        parentNode = this._renderer.parentNode(this._iframe);
      }
    }
    return parentNode;
  }

  private stopListening() {
    this._iframe = null;
    this._windowMessageListener();
  }

  private authByUrl(url: string): Promise<any> {
    return new Promise((resolve, reject) => {
      this._time = Date.now();
      try {
        this._authType.getTokenFromUrl(url, (token) => {
          if (!this._authType.isValidToken(token, this._time)) throw 'Invalid authent.';
          this._status = PeAuthService.CXN_SUCCESS;
          this._token  = token;
          this._cookieOptions.expires = new Date(Date.now()+86400000);
          this.cookieService.putObject(this._authType.cookieName, this._token, this._cookieOptions);
          resolve();
        });
      } catch (e) {
        reject(e);
      }
    });
  }

  private recievedMessage = (e: any, refreshToken: boolean) => {
    const parentNode = this.getIframeParentNode(); 
    if (!parentNode) {
        this.stopListening();
    } else {
      const isWindow = this._iframe.window === this._iframe;
      const win = isWindow ? this._iframe: this._iframe.contentWindow;
      if (e.origin === window.location.origin && e.source === win && e.data !== null && e.data.startsWith(this.peAuthTypeFactory.redirectUrl)) {
        this.ngZone.run(()=>{
          const promise = new Promise<boolean>((resolve, reject) => {
            let reloaded = false;
            this.authByUrl(e.data).then(() => {
              resolve(reloaded);
            }).catch(() => {
              if (reloaded = this._authType.autoReload) {
                if (this._nbAttempt === this.peAuthTypeFactory.maxRetry) {
                  this._status = PeAuthService.CXN_MAX_RETRY;
                  reloaded = false;
                } else {
                  this._nbAttempt++;
                  this._subject.next({ status: this._status, token: this._token, refreshToken: refreshToken, attempt: this._nbAttempt });
                  win.location.href = this._authType.cxnUrl;
                }
              } else {
                this._status = PeAuthService.CXN_ECHEC;
              }
              resolve(reloaded);
            });
          });
          
          promise.then(reloaded => {
            if (!reloaded) {
              if (isWindow) {
                win.close();
              } else {
                this._renderer.removeChild(parentNode, this._iframe);
              }
              this.stopListening();
              this.afterCxn(this._token, this._status, refreshToken);
            }  
          });
        });
      }
    }
  }

  private iframeLoaded = (e:any) => {
    setTimeout(() => {
      try {
        const parentNode = this._renderer.parentNode(this._iframe);
        if (parentNode !== null) {
          const loc = this._iframe.contentWindow.location;
          if (loc.origin + loc.pathname !== this.peAuthTypeFactory.redirectUrl) throw 'Not redirect yet.';
        }
      } catch (e) {
        if (this._iframe) this._renderer.setAttribute(this._iframe, 'class', 'pe-auth-login');
      }
    }, 500);
    this._iframeLoadListener();
  }

  private auth(container: HTMLElement, refreshToken: boolean): void {
    let isCxnUrl = this._authType.cxnUrl !== null;
    if (isCxnUrl) {
      this._windowMessageListener = this._renderer.listen(window, 'message', e => this.recievedMessage(e, refreshToken));
      switch (this.peAuthTypeFactory.connectBy) {
        case 'iframe':
          //remove iframe if exists in DOM
          const parentNode = this.getIframeParentNode();
          if (parentNode) this._renderer.removeChild(parentNode, this._iframe);
          
          //Construct new iframe
          this._iframe = this._renderer.createElement('iframe');
          this._renderer.setAttribute(this._iframe, 'class', 'pe-auth');
          this._renderer.setAttribute(this._iframe, 'src', this._authType.cxnUrl);
          
          this._iframeLoadListener = this._renderer.listen(this._iframe, 'load', this.iframeLoaded);

          //fix stylesheets
          const encapsulationAttr = getEncapsulationAttr(container);
          if (encapsulationAttr !== null) this._renderer.setAttribute(this._iframe, encapsulationAttr, '');
  
          this._renderer.appendChild(container, this._iframe);
          break;
      
        case 'window':
          this._iframe = window.open(this._authType.cxnUrl, "authWin");
          break;

        default:
          this.stopListening();
          break;
      }
    }

    this.ngZone.run(()=>{
      if (!isCxnUrl) {
        setTimeout(()=> {
          this._status = PeAuthService.CXN_ECHEC;
          this._subject.next({ status: this._status, token: this._token, refreshToken: refreshToken, attempt: this._nbAttempt });
        }, 0);
      }
    });
  }


  private authByCookie(): boolean {
    const cookie = this.cookieService.getObject(this._authType.cookieName);
    if (cookie) {
      try {
        const token = this._authType.getTokenFromCookie(cookie);
        if (!this._authType.isValidToken(token, this._time)) throw 'Invalid authent.';
        this.ngZone.run(()=>{
          this._status = PeAuthService.CXN_SUCCESS;
          this._token  = token;
          this.afterCxn(this._token, this._status, false);
        });
        return true;
      } catch (e) {
        this.cookieService.remove(this._authType.cookieName, this._cookieOptions);
      }
    }
    return false;
  }
   
}
