import { Injectable } from '@angular/core';
import { Router, CanActivate, ActivatedRouteSnapshot, RouterStateSnapshot } from '@angular/router';
import { PeAuthService } from './pe-auth.service';
import { NavigationEnd, NavigationExtras } from '@angular/router';

import { Observable } from 'rxjs';
import { PeInterceptService } from './pe-intercept.service';

@Injectable()
export class PeAuthGuardService implements CanActivate {

	constructor(private router: Router, private peAuthService: PeAuthService, private peInterceptService: PeInterceptService) {
		router.events.subscribe(e => {
      if (e instanceof NavigationEnd) this.peInterceptService.clear(e);
    });
	}

	canActivate(route: ActivatedRouteSnapshot, state: RouterStateSnapshot): Observable<boolean> | Promise<boolean> | boolean {
		if (!this.peAuthService.isConnected()) {
			this.peInterceptService.secureRoute = state;
			let opts: NavigationExtras = {};
			if (route) opts.queryParams = route.queryParams
      this.router.navigate(this.peAuthService.loginRoute, opts).catch(this.peInterceptService.clear);
			return false;
		}
		return true;
	}

}