import { Injectable, Inject } from "@angular/core";
import { AUTH_OPTIONS, PeAuthOptions, WebSSOOptions, KitSSOOptions, OpenAMOptions, NetEntrepriseOptions } from "../declarations/pe-auth.options";
import { WebSSOType } from "../auth-types/webSSO.type";
import { KitSSOType } from "../auth-types/kitSSO.type";
import { OpenAMType } from "../auth-types/openAM.type";
import { NetEntrepriseType } from "../auth-types/netEntreprise.type";
import { HttpClient } from "@angular/common/http";
import { LocationStrategy, HashLocationStrategy, PathLocationStrategy } from "@angular/common";
import { PeAuthType } from "../declarations"


@Injectable()
export class PeAuthTypeFactory {

  private _authOptions: PeAuthOptions;

  static readonly MODE_AGENT = 'agent';
  static readonly MODE_EMPLOYEUR = 'employeur';
  static readonly MODE_INDIVIDU = 'individu';
  static readonly MODE_PARTENAIRE = 'partenaire';
  
  static readonly AUTH_WEBSSO = 'webSSO';
  static readonly AUTH_KITSSO = 'kitSSO';
  static readonly AUTH_NET_ENTREPRISE = 'netEntreprise';
  static readonly AUTH_PEAM   = 'openAM';

  constructor(@Inject(AUTH_OPTIONS) options: PeAuthOptions, private http: HttpClient, private locationStrategy: LocationStrategy) {
    this._authOptions = options;
    if (!options.redirectUrl.startsWith('http')) this.buildRedirectPath();
  }

  get redirectUrl() {
    return this._authOptions.redirectUrl;
  }

  get loginRoute() {
    return this._authOptions.loginRoute;
  }

  get connectBy() {
    return this._authOptions.connectBy ? this._authOptions.connectBy : 'iframe';
  }

  get maxRetry() {
    return this._authOptions.maxRetry ? this._authOptions.maxRetry : 5;
  }

  getPeAuthType(type: string, mode: string): PeAuthType {
    switch (type) {
            
      //AUTH WEBSSO
      case PeAuthTypeFactory.AUTH_WEBSSO:
        if (!(mode === PeAuthTypeFactory.MODE_AGENT))
        throw 'Invalid authentification : ' + mode + ' does not exist for type' + type + '.';
      
        const webSSOOptions: WebSSOOptions = this._authOptions.webSSO[mode];
        return new WebSSOType(webSSOOptions, mode, this._authOptions.redirectUrl);
      
      //AUTH KITSSO
      case PeAuthTypeFactory.AUTH_KITSSO:
        if (!(mode === PeAuthTypeFactory.MODE_AGENT))
        throw 'Invalid authentification : ' + mode + ' does not exist for type' + type + '.';
      
        const kitSSOOptions: KitSSOOptions = this._authOptions.kitSSO[mode];
        return new KitSSOType(kitSSOOptions, mode, this._authOptions.redirectUrl);

      //AUTH NETENTREPRISE
      case PeAuthTypeFactory.AUTH_NET_ENTREPRISE:
        if (!(mode === PeAuthTypeFactory.MODE_PARTENAIRE))
        throw 'Invalid authentification : ' + mode + ' does not exist for type' + type + '.';
      
        const netEntrepriseOptions: NetEntrepriseOptions = this._authOptions.netEntreprise[mode];
        return new NetEntrepriseType(netEntrepriseOptions, mode, this._authOptions.redirectUrl);

      //AUT OPENAM
      case PeAuthTypeFactory.AUTH_PEAM:
        if (!(mode === PeAuthTypeFactory.MODE_AGENT || mode === PeAuthTypeFactory.MODE_EMPLOYEUR || mode === PeAuthTypeFactory.MODE_INDIVIDU || mode === PeAuthTypeFactory.MODE_PARTENAIRE))
        throw 'Invalid authentification : ' + mode + ' does not exist for type' + type + '.';    

        const openAMOptions: OpenAMOptions = this._authOptions.openAM[mode];
        return new OpenAMType(openAMOptions, mode, this._authOptions.redirectUrl, this.http);

      default:
        throw 'Invalid authentification : ' + type + ' does not exist.';
    }
  }

  private buildRedirectPath() {
    let baseHref = '';
    if (this.locationStrategy instanceof HashLocationStrategy) {
      baseHref = window.location.pathname;
    } else if (this.locationStrategy instanceof PathLocationStrategy) {
      baseHref = this.locationStrategy.getBaseHref();
    }
    baseHref =  baseHref ? (baseHref.endsWith('/') ? baseHref.substring(0, baseHref.length - 1) : baseHref ) :''; 
    this._authOptions.redirectUrl = window.location.origin + baseHref + this._authOptions.redirectUrl;
  }
}