import { PeAuthFlow } from "./pe-auth-flow";
import { searchParams } from '../../utils/utils';
import { HttpClient, HttpHeaders } from "@angular/common/http";
import { OpenAMOptions } from "../../declarations/pe-auth.options";

export class AuthorizationCodeFlow implements PeAuthFlow {

    private http: HttpClient;
    private _options: OpenAMOptions
    private _redirect_uri: string;
    private _state: string;

    constructor(http: HttpClient, openAMOptions: OpenAMOptions, state: string, redirect_uri: string) {
        this.http = http;
        this._options = openAMOptions;
        this._redirect_uri = redirect_uri;
        this._state = state;
    }

    getTokenFromUrl(url: any, callback: (token:any) => void) {
        const urlParams = searchParams(url);
        if (urlParams['state'] === this._state && urlParams.hasOwnProperty('code')) {
            const body = [
              `grant_type=authorization_code`,
              `code=${urlParams['code']}`,
              `client_id=${this._options.clientId}`,
              `redirect_uri=${encodeURIComponent(this._redirect_uri)}`,
            ].join('&');
            const authorizeResource = this._options.authorizeResource;
            const accessTokenUrl = authorizeResource.accessTokenUrl ? (this._options.openAMUrl + authorizeResource.accessTokenUrl) : authorizeResource.externalAccessTokenUrl;
            if (!accessTokenUrl) throw "accessTokenUrl or externalAccessTokenUrl is required in configurations";
            this.http.post(accessTokenUrl, body , {
              headers: new HttpHeaders({
                  "Content-Type": "application/x-www-form-urlencoded"
              }),
            }).subscribe( data => callback(data), resp => callback(null));
        } else {
            callback(null);
        }

    }
    
    isValidToken(token:any, time: number, state: string, nonce: string) {
        return token['nonce'] === nonce && parseInt(token['expires_in']) * 1000 + time > Date.now();
    };
}